K-matrix.css:
*{margin:0;padding:0;box-sizing:border-box}
body{background:__BG_EXT__;display:flex;justify-content:center;padding:40px 0;font-family:-apple-system,'Microsoft YaHei','PingFang SC',sans-serif;-webkit-font-smoothing:antialiased}
.page{width:210mm;min-height:297mm;background:__BG__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.05);position:relative;overflow:hidden}
@media print{body{background:#fff;padding:0}.page{box-shadow:none;margin:0;width:210mm;min-height:297mm}}

.hero-matrix{background:linear-gradient(160deg,__HERO_BG1__,__HERO_BG2__);padding:36px 20mm 28px;color:__HERO_TEXT__;clip-path:polygon(0 0,100% 0,100% 92%,0 100%)}
.hero-matrix h1{font-size:38pt;font-weight:800;letter-spacing:0.06em}
.hero-matrix .sub{font-size:10pt;color:__HERO_MUTED__;margin-top:6px;letter-spacing:0.04em}
.hero-matrix .contact{display:flex;gap:20px;margin-top:10px;font-size:8pt;color:__HERO_DIM__}
.matrix-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;padding:20px 18mm}
.matrix-cell{background:__CARD__;border-radius:6px;padding:16px;border-left:4px solid __ACCENT__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.matrix-cell h3{font-size:11pt;color:__TEXT_DARK__;margin-bottom:6px}
.matrix-cell .items{display:flex;flex-wrap:wrap;gap:4px}
.matrix-chip{background:__TAG__;color:__ACCENT__;padding:3px 10px;border-radius:3px;font-size:7.5pt;border:0.5px solid __ACCENT__30}
.exp-strip{padding:16px 18mm;display:flex;flex-direction:column;gap:10px}
.exp-strip .row{display:flex;align-items:center;gap:12px;padding:8px 14px;background:__CARD2__;border-radius:4px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.exp-strip .row .date{font-size:8pt;color:__ACCENT__;min-width:70px;font-weight:600}
.exp-strip .row .info{flex:1}
.exp-strip .row .info b{font-size:11pt;color:__TEXT_DARK__}
.exp-strip .row .info span{font-size:8.5pt;color:__MUTED1__;margin-left:8px}
.foot-strip{padding:10px 18mm;border-top:1px solid __BORDER2__;font-size:7pt;color:__MUTED4__;display:flex;justify-content:space-between}

L-compare.css:
*{margin:0;padding:0;box-sizing:border-box}
body{background:__BG_EXT__;display:flex;justify-content:center;padding:40px 0;font-family:-apple-system,'Microsoft YaHei','PingFang SC',sans-serif;-webkit-font-smoothing:antialiased}
.page{width:210mm;min-height:297mm;background:__BG__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.05);position:relative;overflow:hidden}
@media print{body{background:#fff;padding:0}.page{box-shadow:none;margin:0;width:210mm;min-height:297mm}}

.header-bar{background:__ACCENT__;padding:24px 20mm;color:#fff;display:flex;justify-content:space-between;align-items:flex-end}
.header-bar h1{font-size:34pt;font-weight:800;letter-spacing:0.05em}
.header-bar .meta{font-size:9pt;opacity:0.85;text-align:right}
.compare-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;padding:20px 18mm}
.compare-col h2{font-size:10pt;color:__ACCENT__;letter-spacing:0.08em;text-transform:uppercase;padding:8px 12px;background:__TAG__;border-radius:4px;margin-bottom:12px}
.compare-card{background:__CARD__;padding:14px 16px;margin-bottom:10px;border-radius:4px;border-left:3px solid __ACCENT__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.compare-card .title{font-size:11pt;font-weight:700;color:__TEXT_DARK__}
.compare-card .sub{font-size:8.5pt;color:__MUTED1__;margin-bottom:4px}
.compare-card .date{font-size:7pt;color:__ACCENT__;font-weight:600}
.skills-bar{display:flex;flex-wrap:wrap;gap:6px;padding:12px 18mm;background:__TAG__;border-top:1px solid __BORDER__;border-bottom:1px solid __BORDER__}
.skills-bar .sk{background:__CARD__;padding:5px 14px;border-radius:3px;font-size:8pt;color:__ACCENT__;border:0.5px solid __ACCENT__25}

O-dashboard.css:
*{margin:0;padding:0;box-sizing:border-box}
body{background:__BG_EXT__;display:flex;justify-content:center;padding:40px 0;font-family:-apple-system,'Microsoft YaHei','PingFang SC',sans-serif;-webkit-font-smoothing:antialiased}
.page{width:210mm;min-height:297mm;background:__BG__;box-shadow:0 0 0 0.5px rgba(0,0,0,0.05);position:relative;overflow:hidden}
@media print{body{background:#fff;padding:0}.page{box-shadow:none;margin:0;width:210mm;min-height:297mm}}

.dash-header{background:linear-gradient(135deg,__HERO_BG1__,__HERO_BG2__);padding:30px 20mm 24px;color:__HERO_TEXT__;display:flex;justify-content:space-between;align-items:flex-end}
.dash-header h1{font-size:34pt;font-weight:800;letter-spacing:0.04em}
.dash-header .sub{font-size:9pt;color:__HERO_MUTED__;letter-spacing:0.04em}
.dash-kpi{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;padding:16px 18mm;margin-top:-12px;position:relative;z-index:2}
.dash-kpi .kpi{background:__CARD__;border-radius:6px;padding:14px;text-align:center;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__;border-top:3px solid __ACCENT__}
.dash-kpi .kpi .num{font-size:28pt;font-weight:900;color:__ACCENT__;line-height:1}
.dash-kpi .kpi .lbl{font-size:7pt;color:__MUTED1__;margin-top:4px;letter-spacing:0.06em}
.dash-body{display:grid;grid-template-columns:1fr 1fr;gap:14px;padding:8px 18mm 20px}
.dash-panel{background:__CARD__;border-radius:6px;padding:16px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.dash-panel h3{font-size:10pt;color:__ACCENT__;letter-spacing:0.08em;margin-bottom:12px;text-transform:uppercase}
.dash-panel .bar-row{display:flex;align-items:center;margin-bottom:8px;gap:8px}
.dash-panel .bar-row .label{font-size:8pt;color:__TEXT__;min-width:55px}
.dash-panel .bar-row .bar{flex:1;height:6px;background:__TAG__;border-radius:3px;overflow:hidden}
.dash-panel .bar-row .bar .fill{height:100%;background:__ACCENT__;border-radius:3px}
.dash-timeline{padding:0 18mm 20px}
.dash-timeline .tl-row{display:flex;align-items:center;padding:8px 14px;margin-bottom:6px;background:__CARD2__;border-radius:4px;gap:12px;box-shadow:0 0 0 0.5px rgba(0,0,0,0.06);border:0.5px solid __BORDER__}
.dash-timeline .tl-row .yr{font-size:10pt;font-weight:700;color:__ACCENT__;min-width:55px}
.dash-timeline .tl-row .desc{font-size:9pt;color:__TEXT__}
